// Validate and extract document fields
const body = $input.first().json.body;
if (!body.content || !body.filename) {
  throw new Error('Missing required fields: content and filename');
}

// Clean text – remove excess whitespace
const cleaned = body.content.replace(/\s+/g, ' ').trim();

// Chunk into 512-token segments with 50-token overlap
const chunkSize = 512;
const overlap = 50;
const words = cleaned.split(' ');
const chunks = [];
for (let i = 0; i < words.length; i += chunkSize - overlap) {
  const chunk = words.slice(i, i + chunkSize).join(' ');
  if (chunk.trim().length > 0) {
    chunks.push({
      chunk_id: `${body.filename}_${i}`,
      text: chunk,
      source: body.source || body.filename,
      filename: body.filename,
      chunk_index: chunks.length
    });
  }
}
return chunks.map(c => ({ json: c }));

// Extract embedding from OpenAI response and merge with chunk metadata
const chunk = $('Code – Clean & Chunk Text').item.json;
const embeddingData = $input.first().json;
const vector = embeddingData.data[0].embedding;
return [{
  json: {
    chunk_id: chunk.chunk_id,
    text: chunk.text,
    source: chunk.source,
    filename: chunk.filename,
    chunk_index: chunk.chunk_index,
    embedding: vector,
    indexed_at: new Date().toISOString()
  }
}];

// Build context string from top-k retrieved chunks
const matches = $input.first().json.matches || [];
const question = $('Webhook – Query').item.json.body.question;

// Sort by score descending, filter low-confidence results
const filtered = matches
  .filter(m => m.score > 0.7)
  .sort((a, b) => b.score - a.score);

if (filtered.length === 0) {
  return [{ json: { context: '', question, no_results: true } }];
}

const context = filtered
  .map((m, i) => `[Source ${i+1}: ${m.metadata.source}]\n${m.metadata.text}`)
  .join('\n\n---\n\n');

const sources = [...new Set(filtered.map(m => m.metadata.source))];
return [{ json: { context, question, sources, chunk_count: filtered.length } }];

